// Read up to 10 source files from the given path.
// Requires self-hosted n8n (filesystem access via require('fs')).
const fs = require('fs');
const nodePath = require('path');

const targetPath = $input.first().json.body?.path || $input.first().json.path;
if (!targetPath) throw new Error('No path provided. POST body must include { "path": "/your/path" }');

const SOURCE_EXTS = new Set(['.py','.js','.ts','.jsx','.tsx','.go','.rs','.java','.rb','.php','.c','.cpp','.cs','.swift']);
const MAX_FILES = 10;
const MAX_CHARS = 4000;

function collectFiles(p) {
  const stat = fs.statSync(p);
  if (stat.isFile()) return [p];
  const results = [];
  for (const entry of fs.readdirSync(p).sort()) {
    if (results.length >= MAX_FILES) break;
    if (entry.startsWith('.') || ['__pycache__','node_modules','venv','.git'].includes(entry)) continue;
    const full = nodePath.join(p, entry);
    const s = fs.statSync(full);
    if (s.isFile() && SOURCE_EXTS.has(nodePath.extname(full))) results.push(full);
  }
  return results;
}

const files = collectFiles(targetPath);
if (files.length === 0) throw new Error('No source files found at: ' + targetPath);

const content = files.map(f => {
  const text = fs.readFileSync(f, 'utf8').slice(0, MAX_CHARS);
  return `=== ${f} ===\n${text}`;
}).join('\n\n');

return [{ json: { target_path: targetPath, files, file_count: files.length, content } }];

// Parse JSON from each agent's raw text response.
// Uses 3-strategy fallback: fenced block → whole text → largest {…}
function parseJSON(text) {
  if (!text) return {};
  // Strategy 1: fenced block
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) { try { return JSON.parse(m[1].trim()); } catch(e) {} }
  // Strategy 2: whole text
  try { return JSON.parse(text.trim()); } catch(e) {}
  // Strategy 3: largest { } block
  let best = '', depth = 0, start = -1;
  for (let i = 0; i < text.length; i++) {
    if (text[i] === '{') { if (depth++ === 0) start = i; }
    else if (text[i] === '}' && depth > 0) {
      if (--depth === 0) { const c = text.slice(start, i+1); if (c.length > best.length) best = c; }
    }
  }
  if (best) { try { return JSON.parse(best); } catch(e) {} }
  return {};
}

const target    = $('Read Source Files').first().json.target_path;
const analysis  = parseJSON($('Analyzer').first().json.message?.content);
const review    = parseJSON($('Reviewer').first().json.message?.content);
const suggestions = parseJSON($('Suggester').first().json.message?.content);
const summary   = parseJSON($('Summarizer').first().json.message?.content);

return [{ json: {
  target_path: target,
  generated_at: new Date().toISOString(),
  overall_score:      summary.overall_score      || 50,
  executive_summary:  summary.executive_summary  || '',
  critical_findings:  summary.critical_findings  || [],
  top_improvements:   summary.top_improvements   || [],
  analysis,
  review,
  suggestions
} }];
